INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05560', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列對於「新管理主義」（New Managerialism）的描述，何者正確？', '["因為公共服務進入強制性競標而造成準市場失靈的現象，新管理主義因此誕生", "經濟、效率與效能是其所追求的目標，強調契約化、消費主義、競爭等", "為免除因科層－專業主義所導致的冷酷無情，新管理主義強調不再僱用具有社會工作專業知識與技能 的專業者", "重視社區的參與，強調地方政府與社區之間夥伴關係的建立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05561', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列對於「最佳價值」（The Best Value）的描述，何者錯誤？', '["視社會為一個競逐利益的市場，而非具有共同目標的社區", "企圖將一種理性的規劃與評估觀點引進地方政府的管理，可說是跨足新管理主義與社區和地方治理的 產物", "重視全面性績效評估", "重視地方政府與外部立契約者之間要建立關係契約，即彼此應具有互信、互賴、合作等基礎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05562', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '將管理理論運用於社會工作時，下列何者適用於處理問題複雜且多變的社會服務機構？', '["科層管理", "權變理論", "學習型組織", "系統理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05563', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '倫理是社會工作服務難以避免的議題，社會工作管理者亦會遭遇倫理的挑戰。下列對於倫理情境之描述， 何者正確？', '["「社會工作倫理」涉及分配正義的議題，「社會工作管理倫理」則是處理直接服務的兩難議題", "依契約行事，但是機構的人事政策可能造成性別歧視，此為「社會工作倫理」的議題", "社會工作管理者會面對的倫理困境主要為機構內部的勞雇關係、資源分配等議題，不會涉及與外部組 織的互動", "機構因預算刪減而須做出如何配置有限資源及誰的需求應被優先考量的抉擇，此為「社會工作管理倫 理」的議題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05564', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理一個部門或組織所需的能力可分為概念性技能、技術性技能與人群關係技能，管理者須因其所處的 組織情境與位階層級來做不同技能展現的彈性調整。下列關於管理層級與管理技能的描述，何者正確？', '["部門總監為高階管理者，首重規劃組織方向與目標的能力，因此不需具備與員工相處的技能", "機構主任為中階管理者，需具備完成上級交代工作以及適時反應第一線所發生問題的能力", "機構督導為基層管理者，具備訓練與領導基層員工、監督日常工作活動等技能是相對重要的", "無論是何種管理階層，具備技術性技能是同等重要的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05565', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '人力資源規劃（human resource planning）是人力資源管理活動中重要的一環，意即能做出系統且持續性 的分析過程，則能為組織取得必要的人力。為達此目標，人力資源規劃的步驟應為：', '["分析人力特性→預測組織走向→需要何種人才進入組織", "預測組織走向→需要何種人才進入組織→分析人力特性", "分析人力特性→需要何種人才進入組織→預測組織走向", "預測組織走向→分析人力特性→需要何種人才進入組織"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05566', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列有關組織決策的敘述，何者錯誤？', '["社會工作的實施經常強調案主參與原則，所以社會福利機構會邀請社區居民來參與決策", "當組織遇有多重且複雜的問題要處理時，最好採取問題解決的決策類型", "直覺的決策類型速度快且不易流入人性偏見導致誤判資訊", "採用個人決策省時省力且責任明確"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05567', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某社會服務機構團隊進駐甲縣，經過一週後，該團隊依據甲縣內兩個家庭福利服務中心過去 2 年所提供 的服務項目與服務人次統計，規劃出為期一年的親子互動桌遊方案。該團隊用以規劃方案的需求評估主 要基於那個觀點？', '["規範性需求", "相對性需求", "感受性需求", "表達性需求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05568', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '志工運用是社會服務機構中重要的人力資源。下列對於志工管理模式的描述，何者正確？', '["傳統模式（Traditional Model）與麥格雷戈（McGregor）所提出的Y理論相似，認為人是不喜歡工作的， 因此需要監督與控制", "人力資源模式（Human Resources Model）與志工期待以尊重、情感來管理的理念較契合", "人群關係模式（Human Relations Model）較關注志工的需求與注重個別差異，強調以符合人性的管理方 式來激發志工的潛能", "志願服務的中心思想是個人自動自發的參與服務活動，因此管理時應以促進情感交流為主，避免訓練 發展課程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05569', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '做方案規劃時必須作需求評估，一般而言我們常採用Bradshaw（1972）的四種需求分類來進行需求測量， 下列那一種需求測量方法是運用感受性需求（Felt Need）的方法？', '["以實際尋求協助的人數來界定需求", "由專業學者或權威專家來界定需求", "辦理公聽會來了解社區的需求及問題所在", "比較地理環境及人口組成類似的兩個社區之間現有服務的差距來說明需求的存在"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
